// Auto-generated from public/sounds/{buddyin,buddyout,imrcv}.mp3 via base64.
// Why these are inlined instead of referenced by URL: WebKitGTK's custom
// protocol handler on Linux doesn't support HTTP Range requests, which
// <audio>/<video> resource loading requires — any real media file served
// through Tauri's embedded-asset protocol fails there with a WebKit-level
// FormatError before GStreamer ever sees it, confirmed via GST_DEBUG output
// against this exact app. This is an upstream WebKitGTK limitation, not a
// Tauri config issue — see https://github.com/tauri-apps/tauri/issues/3725.
// data: URIs are resolved in-memory with no protocol/Range layer involved,
// so they sidestep the bug entirely. Regenerate if these files ever change:
//   base64 -w0 public/sounds/<name>.mp3

export const buddyinData = "data:audio/mpeg;base64,";
export const buddyoutData = "data:audio/mpeg;base64,";
export const imrcvData = "data:audio/mpeg;base64,";
export const ringData = "data:audio/mpeg;base64,";
export const imsendData = "data:audio/mpeg;base64,";
export const welcomeData = "data:audio/mpeg;base64,";
export const goodbyeData = "data:audio/mpeg;base64,";
